INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-d35ec6db-moex-00207', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '關於表見代理與無權代理，下列敘述何者錯誤？', '["關於表見代理，如其相對人不主張適用表見代理者，仍應適用狹義無權代理", "事實行為亦得成立表見代理", "相對人得對無權代理人請求損害賠償者，須相對人自己屬於善意，亦即於無權代理行為成立時， 對於無權代理並不知情", "有關民法第110條之賠償範圍，相對人得請求信賴利益之損害賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00208', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲蛋商向乙蛋雞場訂購100箱雞蛋，預定二週後交貨，甲已先給付價金新臺幣5萬元。豈料該蛋 雞場遭受H5N2高病原性禽流感危害，整場雞隻遭到全面撲殺，乙因此無法如期給付。關於給付 不能之敘述，下列何者錯誤？', '["蛋雞場遭受禽流感危害，雞隻遭到全面撲殺，乃屬於不可歸責雙方當事人所致之給付不能", "由甲負擔給付不能時之給付危險", "由乙負擔給付不能時之價金危險", "由於甲負擔給付危險，因此乙無須返還甲已支付之5萬元價金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00209', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲乙係鄰居，某日乙外出旅遊，家中無人，因電線走火引起火災。甲為撲滅火源，致乙家中之電 視浸水而受有損害，且甲因此受傷。下列敘述何者錯誤？', '["甲之救火行為係未受委任，亦無義務，而為他人管理事務", "甲之救火行為係利於乙本人，且不違反乙可得推知之意思", "甲因救火行為而受傷，得向乙請求損害賠償", "乙家中電視之損害，乙得向甲請求賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00210', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲人力仲介公司受乙工廠委託，引進外勞丙並辦理就業服務。關於僱傭之敘述，下列何者錯誤？', '["甲仲介外勞丙至乙工廠服務，僱傭關係乃存在於乙丙之間", "乙因工廠整建以致無法如期讓丙上工，丙仍須補服勞務", "丙因工廠設備故障而身體受傷，丙得向乙請求損害賠償", "丙因家人病故須返回母國，得於僱傭期限屆滿前終止契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00211', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲之馬戲團以猛獸表演著稱，某日表演時，因甲僱用之馴獸師乙不注意，讓猛獸逃脫至觀眾席， 因而咬傷觀眾丙。下列敘述何者正確？', '["甲為猛獸之直接占有人，故須對丙負損害賠償責任", "乙為猛獸之直接占有人，故須對丙負損害賠償責任", "甲為猛獸之占有輔助人，故無須對丙負損害賠償責任", "乙為猛獸之間接占有人，故無須對丙負損害賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00212', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '關於連帶債權之敘述，下列何者正確？', '["連帶債權僅得依法律規定而生", "連帶債權之債務人須向全體債權人為全部給付", "連帶債權人中之一人受領遲延者，其他債權人亦負其責任", "連帶債權人中之一人，向債務人免除全部債務者，債權消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00213', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '富二代甲受友人乙邀約，至丙開設之娛樂公司進行博弈消費，一晚豪賭後輸了新臺幣（下同）500 萬元，甲遂簽立借據並簽發500萬元本票於丙；其後，丙將該債權、借據及本票以400萬元讓售 於債務催收公司丁。事後丁提示借據及本票向甲催收時，甲反控遭乙、丙二人詐賭，認為「賭債 非債」，本票債權不存在。下列敘述何者正確？', '["丙讓與債權於丁，因丙未通知甲，故對甲不生債權讓與效力", "甲所簽立之借據，因無借款之真意，故甲得撤銷該借據", "甲所簽發之本票，因本票債權違反公序良俗無效，故該本票亦為無效", "丙以無效之債權讓售於丁，須對丁負權利瑕疵擔保之責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00214', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何者為要約？', '["商品在報章雜誌廣告", "量販店寄送之價目表", "小吃店標示有價格之「請自取」的小菜", "車展中標示價格展示之汽車"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00215', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '關於租賃之敘述，下列何者錯誤？', '["租賃關係存續中，因不可歸責於出租人及承租人之事由，致租賃物一部滅失時，承租人得按滅 失之部分，請求減少租金", "承租人因病住院，致不能為租賃物全部之使用收益時，不得因此免其支付租金之義務", "承租人租用A屋，與出租人約定租金為每個月新臺幣1萬元，且按月於月初支付。承租人遲付 租金之總額已達2個月之租額時，出租人得逕終止契約", "租賃物之修繕，得約定由出租人與承租人平均負擔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00216', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '關於添附之敘述，下列何者錯誤？', '["加工於他人之動產者，其加工物之所有權屬於加工人。但因材料之價值顯逾加工所增之價值者， 其加工物之所有權屬於材料所有人", "動產與他人之動產附合，非毀損不能分離或分離需費過鉅者，若無其他條件，各動產所有人按 其動產附合時之價值，共有合成物", "動產與他人之動產混合，不能識別或識別需費過鉅者，若無其他條件，各動產所有人按其動產 混合時之價值，共有混合物", "動產因附合而為不動產之重要成分者，不動產所有權人取得動產所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
